package org.eclipse.rdf4j.sail.memory;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.eclipse.rdf4j.sail.memory.model.MemIRI;
import org.eclipse.rdf4j.sail.memory.model.MemResource;
import org.eclipse.rdf4j.sail.memory.model.MemStatementList;
import org.eclipse.rdf4j.sail.memory.model.MemValue;
import org.eclipse.rdf4j.sail.memory.model.MemValueFactory;

/**
 * Uses the MemoryStore's statement sizes to give cost estimates based on the size of the expected results. This process
 * could be improved with repository statistics about size and distribution of statements.
 *
 * @author Arjohn Kampman
 * @author James Leigh
 */
class MemEvaluationStatistics extends EvaluationStatistics {

	private final MemValueFactory valueFactory;
	private final MemStatementList memStatementList;

	MemEvaluationStatistics(MemValueFactory valueFactory, MemStatementList memStatementList) {
		this.valueFactory = valueFactory;
		this.memStatementList = memStatementList;
	}

	@Override
	protected CardinalityCalculator createCardinalityCalculator() {
		return new MemCardinalityCalculator();
	}

	@Override
	public CardinalityEstimate getCardinalityEstimate(TupleExpr expr) {
		if (!(expr instanceof StatementPattern)) {
			return super.getCardinalityEstimate(expr);
		}

		StatementPattern pattern = (StatementPattern) expr;
		double estimate = getCardinality(pattern);
		if (estimate == 0.0) {
			return createCardinalityEstimate(0.0, 0.0, 0.0, 1.0, "memory-synopsis");
		}

		Resource subj = asResource(pattern.getSubjectVar());
		IRI pred = asIri(pattern.getPredicateVar());
		Value obj = constantValue(pattern.getObjectVar());
		Resource context = asResource(pattern.getContextVar());

		double totalCardinality = memStatementList.size();
		double selectivityDenominator = Math.max(1.0, totalCardinality);
		double synopsisUpperBound = totalCardinality;
		double independenceEstimate = totalCardinality;
		int boundDimensions = 0;

		if (subj != null) {
			double subjectCount = subjectStatementCount(subj);
			synopsisUpperBound = Math.min(synopsisUpperBound, subjectCount);
			independenceEstimate *= subjectCount / selectivityDenominator;
			boundDimensions++;
		}

		if (pred != null) {
			double predicateCount = predicateStatementCount(pred);
			synopsisUpperBound = Math.min(synopsisUpperBound, predicateCount);
			independenceEstimate *= predicateCount / selectivityDenominator;
			boundDimensions++;
		}

		if (obj != null) {
			double objectCount = objectStatementCount(obj);
			synopsisUpperBound = Math.min(synopsisUpperBound, objectCount);
			independenceEstimate *= objectCount / selectivityDenominator;
			boundDimensions++;
		}

		if (context != null) {
			double contextCount = contextStatementCount(context);
			synopsisUpperBound = Math.min(synopsisUpperBound, contextCount);
			independenceEstimate *= contextCount / selectivityDenominator;
			boundDimensions++;
		}

		double lowerBound;
		double upperBound;
		if (boundDimensions == 0) {
			lowerBound = estimate * 0.5;
			upperBound = estimate;
		} else {
			lowerBound = Math.min(estimate, independenceEstimate);
			upperBound = Math.max(estimate, synopsisUpperBound);
		}

		lowerBound = Math.max(0.0, Math.min(lowerBound, upperBound));
		double spread = upperBound == 0.0 ? 0.0 : (upperBound - lowerBound) / upperBound;
		double confidence = synopsisConfidence(boundDimensions, spread);

		return createCardinalityEstimate(estimate, lowerBound, upperBound, confidence, "memory-synopsis");
	}

	private static double synopsisConfidence(int boundDimensions, double spread) {
		if (boundDimensions == 0) {
			return 0.45;
		}
		double boundedSpread = Math.max(0.0, Math.min(1.0, spread));
		double confidence = 0.7 + (0.2 * (Math.min(boundDimensions, 4) - 1) / 3.0) - (0.25 * boundedSpread);
		return Math.max(0.5, Math.min(0.95, confidence));
	}

	private Value constantValue(Var var) {
		return var != null ? var.getValue() : null;
	}

	private Resource asResource(Var var) {
		Value value = constantValue(var);
		return value instanceof Resource ? (Resource) value : null;
	}

	private IRI asIri(Var var) {
		Value value = constantValue(var);
		return value instanceof IRI ? (IRI) value : null;
	}

	private double subjectStatementCount(Resource subject) {
		MemResource memSubject = valueFactory.getMemResource(subject);
		return memSubject != null ? memSubject.getSubjectStatementCount() : 0.0;
	}

	private double predicateStatementCount(IRI predicate) {
		MemIRI memPredicate = valueFactory.getMemURI(predicate);
		return memPredicate != null ? memPredicate.getPredicateStatementCount() : 0.0;
	}

	private double objectStatementCount(Value object) {
		MemValue memObject = valueFactory.getMemValue(object);
		return memObject != null ? memObject.getObjectStatementCount() : 0.0;
	}

	private double contextStatementCount(Resource context) {
		MemResource memContext = valueFactory.getMemResource(context);
		return memContext != null ? memContext.getContextStatementCount() : 0.0;
	}

	protected class MemCardinalityCalculator extends CardinalityCalculator {

		@Override
		public double getCardinality(StatementPattern sp) {

			Value subj = getConstantValue(sp.getSubjectVar());
			if (!(subj != null && subj.isResource())) {
				// can happen when a previous optimizer has inlined a comparison
				// operator.
				// this can cause, for example, the subject variable to be
				// equated to a literal value.
				// See SES-970 / SES-998
				subj = null;
			}
			Value pred = getConstantValue(sp.getPredicateVar());
			if (!(pred != null && pred.isIRI())) {
				// can happen when a previous optimizer has inlined a comparison
				// operator. See SES-970 / SES-998
				pred = null;
			}
			Value obj = getConstantValue(sp.getObjectVar());
			Value context = getConstantValue(sp.getContextVar());
			if (!(context != null && context.isResource())) {
				// can happen when a previous optimizer has inlined a comparison
				// operator. See SES-970 / SES-998
				context = null;
			}

			if (subj == null && pred == null && obj == null && context == null) {
				return memStatementList.size();
			} else {
				return minStatementCount(subj, pred, obj, context);
			}

		}

		private int minStatementCount(Value subj, Value pred, Value obj, Value context) {
			int minListSizes = Integer.MAX_VALUE;

			if (subj != null) {
				MemResource memSubj = valueFactory.getMemResource((Resource) subj);
				if (memSubj != null) {
					minListSizes = memSubj.getSubjectStatementCount();
					if (minListSizes == 0) {
						return 0;
					}
				} else {
					// couldn't find the value in the value factory, which means that there are no statements with that
					// value
					return 0;
				}
			}

			if (pred != null) {
				MemIRI memPred = valueFactory.getMemURI((IRI) pred);
				if (memPred != null) {
					minListSizes = Math.min(minListSizes, memPred.getPredicateStatementCount());
					if (minListSizes == 0) {
						return 0;
					}
				} else {
					// couldn't find the value in the value factory, which means that there are no statements with that
					// value
					return 0;
				}
			}

			if (obj != null) {
				MemValue memObj = valueFactory.getMemValue(obj);
				if (memObj != null) {
					minListSizes = Math.min(minListSizes, memObj.getObjectStatementCount());
					if (minListSizes == 0) {
						return 0;
					}
				} else {
					// couldn't find the value in the value factory, which means that there are no statements with that
					// value
					return 0;
				}
			}

			if (context != null) {
				MemResource memContext = valueFactory.getMemResource((Resource) context);
				if (memContext != null) {
					minListSizes = Math.min(minListSizes, memContext.getContextStatementCount());
				} else {
					// couldn't find the value in the value factory, which means that there are no statements with that
					// value
					return 0;
				}
			}

			assert minListSizes != Integer.MAX_VALUE : "minListSizes should have been updated before this point";

			return minListSizes;
		}

		protected Value getConstantValue(Var var) {
			if (var != null) {
				return var.getValue();
			}

			return null;
		}
	}

}
